args.query:
SELECT Symbol, days_over_20pct FROM (
  SELECT 'AGMH' AS Symbol, COUNT(*) AS days_over_20pct FROM "AGMH" WHERE Date >= '2019-01-01' AND Date < '2020-01-01' AND Low > 0 AND (High - Low) / Low > 0.2
  UNION ALL SELECT 'ALACU' AS Symbol, COUNT(*) AS days_over_20pct FROM "ALACU" WHERE Date >= '2019-01-01' AND Date < '2020-01-01' AND Low > 0 AND (High - Low) / Low > 0.2
) t;

